import React from 'react';
import { Link } from 'react-router-dom';

export default function Landing() {
	return (
		<div>
			<h1>Landing</h1>
			<nav>
				<ul id="navigation">
					<li>
						<Link to="/">Home</Link>
					</li>
					<li>
						<Link to="/about">About</Link>
					</li>
					<li>
						<Link to="/contact">Contact</Link>
					</li>
				</ul>
			</nav>
		</div>
	);
}
